CREATE TABLE IF NOT EXISTS products (
  id    INTEGER PRIMARY KEY,
  name  TEXT NOT NULL,
  price REAL NOT NULL
);

INSERT INTO products (id, name, price) VALUES
  (42, 'Mechanical Keyboard', 89.00);

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const id = url.pathname.split("/").pop();
    const key = `product:${id}`;

    // 1) Cache-aside: ask KV first
    let product = await env.CACHE.get(key, "json");
    if (product) {
      // HIT: return straight away, no database needed
      return Response.json({ source: "cache", product });
    }

    // 2) MISS: fall back to D1 (the source of truth)
    const { results } = await env.DB
      .prepare("SELECT * FROM products WHERE id = ?")
      .bind(id)
      .all();
    product = results[0] ?? null;
    if (!product) {
      return new Response("Not found", { status: 404 });
    }

    // 3) Re-fill the cache with a 5-minute TTL, then return
    await env.CACHE.put(key, JSON.stringify(product), {
      expirationTtl: 300,
    });
    return Response.json({ source: "database", product });
  },
};

// On any write, update D1 first, then invalidate the cached copy.
async function updateProduct(env, id, data) {
  // 1) Write to the source of truth
  await env.DB
    .prepare("UPDATE products SET name = ?, price = ? WHERE id = ?")
    .bind(data.name, data.price, id)
    .run();

  // 2) Invalidate: delete the stale key so the next read repopulates it
  await env.CACHE.delete(`product:${id}`);
}

// Plain browser fetch - it never talks to KV or D1 directly.
async function loadProduct(id) {
  const res = await fetch(`/api/product/${id}`);
  const data = await res.json();
  // data.source tells you whether it came from "cache" or "database"
  console.log("served from:", data.source);
  return data.product;
}
